// `HashMap::put_spec(old_v, new_v, key, value)` unfolds (it is `open spec`)
// to the single `Map`-extensional fact `new_v == old_v.insert(key, value)`.
// Both conjuncts of the ensures hypothesis therefore pin
// `post1_self_.epmap@` and `post2_self_.epmap@` to the *same* term
// `pre_self_.epmap@.insert(src@, value)`. The disjoint-trigger gap that
// z3 hit at file level disappears if we package the implication as an
// `assert(... ==> ...) by { ... }` whose body case-splits on the
// hypothesis: inside that branch z3 has both `put_spec`s in scope at the
// same time and can chain the two `Map::insert` equalities through one
// shared term. The internal `=~=` step is a `Map`-extensionality
// reminder; the surrounding `assert ... by` discharges the postcondition
// implication directly.
assert(({
    &&& HashMap::put_spec(pre_self_.epmap@, post1_self_.epmap@, src@, value)
    &&& HashMap::put_spec(pre_self_.epmap@, post2_self_.epmap@, src@, value)
}) ==> det_put_equal(r1, r2, post1_self_, post2_self_)) by {
    if HashMap::put_spec(pre_self_.epmap@, post1_self_.epmap@, src@, value)
        && HashMap::put_spec(pre_self_.epmap@, post2_self_.epmap@, src@, value)
    {
        // Both views collapse to the same `Map::insert` term.
        assert(post1_self_.epmap@ == pre_self_.epmap@.insert(src@, value));
        assert(post2_self_.epmap@ == pre_self_.epmap@.insert(src@, value));
        // Transitivity + `Map`-extensionality.
        assert(post1_self_.epmap@ =~= post2_self_.epmap@);
        assert(post1_self_.epmap@ == post2_self_.epmap@);
        // `r1` and `r2` are `()`, a singleton, so unit-equality is trivial.
        assert(r1 == r2);
    }
};
